// Home.js - Redesigned
import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { motion, useScroll, useTransform, AnimatePresence } from 'framer-motion';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';

const techStack = [
  { name: 'React', icon: '⚛️' },
  { name: 'Node.js', icon: '🟢' },
  { name: 'Express', icon: '🚂' },
  { name: 'PHP', icon: '🐘' },
  { name: 'Laravel', icon: '🪶' },
  { name: 'JavaScript', icon: '🟨' },
  { name: 'Bootstrap', icon: '🎨' },
  { name: 'Tailwind', icon: '🌊' },
  { name: 'Git', icon: '🔀' },
  { name: 'GitHub', icon: '🐙' },
  { name: 'VS Code', icon: '💻' },
  { name: 'Figma', icon: '🎯' },
  { name: 'Postman', icon: '📮' },
  { name: 'MySQL', icon: '🐬' },
  { name: 'Python', icon: '🐍' },
  { name: 'Java', icon: '☕' },
];

const floatingTags = [
  'Software Engineer',
  'Full Stack Developer',
  'React.js',
  'Node.js',
  'PHP',
  'Laravel',
  'MySQL',
  'REST API',
  'Clean Code',
  'Problem Solving',
];

const roles = ['Software Engineer', 'Full Stack Developer', 'Web Developer', 'Mobile Developer'];

export default function Home() {
  const [recentProjects, setRecentProjects] = useState([]);
  const [totalProject, setTotalProject] = useState(0);
  const [roleIndex, setRoleIndex] = useState(0);
  const containerRef = useRef(null);
  const { scrollYProgress } = useScroll();
  const opacity = useTransform(scrollYProgress, [0, 0.3], [1, 0]);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    fetch(`${API}/api/projects/recent`)
      .then((r) => r.json())
      .then(setRecentProjects)
      .catch(console.error);

    fetch(`${API}/api/projects/count`)
      .then((r) => r.json())
      .then((d) => setTotalProject(d.total))
      .catch(console.error);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setRoleIndex((prev) => (prev + 1) % roles.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.1, delayChildren: 0.3 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: [0.34, 1.56, 0.64, 1] } },
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');

        * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
        }

        body {
          background: #090909;
          color: #F5F5F5;
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
          min-height: 100vh;
          overflow-x: hidden;
          position: relative;
        }

        /* Leopard Texture Overlay */
        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background-image: 
            radial-gradient(circle at 20% 30%, rgba(255,62,165,0.03) 0%, transparent 50%),
            radial-gradient(circle at 80% 70%, rgba(216,167,177,0.03) 0%, transparent 50%),
            radial-gradient(circle at 50% 50%, rgba(255,124,199,0.02) 0%, transparent 70%);
          opacity: 0.5;
        }

        /* Subtle leopard pattern via CSS */
        .leopard-bg {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.03;
          background-image: 
            radial-gradient(ellipse 3px 2px at 10% 20%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 4px 3px at 30% 40%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 2px 3px at 50% 10%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 3px 2px at 70% 60%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 4px 2px at 90% 30%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 2px 4px at 15% 70%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 3px 3px at 45% 80%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 2px 2px at 65% 20%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 4px 3px at 85% 50%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 3px 2px at 25% 90%, #fff 0%, transparent 100%);
          background-size: 200px 200px;
          background-repeat: repeat;
        }

        .main-content {
          position: relative;
          z-index: 1;
          padding-top: 100px;
        }

        /* Floating Tags */
        .floating-tag {
          position: absolute;
          padding: 8px 20px;
          border-radius: 100px;
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.06);
          backdrop-filter: blur(20px);
          color: rgba(255,255,255,0.7);
          font-size: 0.75rem;
          font-weight: 500;
          letter-spacing: 0.3px;
          font-family: 'Inter', sans-serif;
          white-space: nowrap;
          pointer-events: none;
          user-select: none;
        }

        /* Marquee */
        .marquee-container {
          overflow: hidden;
          width: 100%;
          padding: 20px 0;
          position: relative;
        }

        .marquee-track {
          display: flex;
          gap: 24px;
          animation: marqueeScroll 30s linear infinite;
          width: max-content;
        }

        .marquee-track:hover {
          animation-play-state: paused;
        }

        @keyframes marqueeScroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }

        .tech-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 12px 24px;
          border-radius: 16px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.06);
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          flex-shrink: 0;
          cursor: default;
        }

        .tech-item:hover {
          background: rgba(255,62,165,0.08);
          border-color: rgba(255,62,165,0.2);
          transform: translateY(-2px);
          box-shadow: 0 8px 32px rgba(255,62,165,0.08);
        }

        .tech-item .icon {
          font-size: 1.4rem;
          line-height: 1;
        }

        .tech-item .name {
          font-family: 'Inter', sans-serif;
          font-weight: 500;
          font-size: 0.85rem;
          color: #F5F5F5;
          letter-spacing: -0.2px;
        }

        /* Project Card */
        .project-card {
          background: rgba(255,255,255,0.03);
          border-radius: 24px;
          border: 1px solid rgba(255,255,255,0.06);
          overflow: hidden;
          transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
          height: 100%;
          position: relative;
        }

        .project-card:hover {
          transform: translateY(-8px) scale(1.01);
          border-color: rgba(255,62,165,0.15);
          box-shadow: 0 20px 60px rgba(255,62,165,0.06);
        }

        .project-card-img {
          width: 100%;
          height: 220px;
          object-fit: cover;
          transition: all 0.6s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .project-card:hover .project-card-img {
          transform: scale(1.03);
        }

        .project-card-body {
          padding: 24px;
        }

        .project-card-title {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 700;
          font-size: 1.1rem;
          color: #F5F5F5;
          margin-bottom: 4px;
        }

        .project-card-desc {
          font-family: 'Inter', sans-serif;
          font-size: 0.85rem;
          color: rgba(255,255,255,0.5);
          line-height: 1.6;
          margin-bottom: 16px;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }

        .project-tech-badge {
          display: inline-block;
          padding: 4px 12px;
          border-radius: 100px;
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.06);
          font-family: 'Inter', sans-serif;
          font-size: 0.7rem;
          font-weight: 500;
          color: rgba(255,255,255,0.6);
          margin: 2px 4px 2px 0;
          transition: all 0.3s ease;
        }

        .project-tech-badge:hover {
          background: rgba(255,62,165,0.08);
          border-color: rgba(255,62,165,0.15);
          color: #FF7CC7;
        }

        .project-card-links {
          display: flex;
          gap: 8px;
          margin-top: 16px;
          flex-wrap: wrap;
        }

        .project-card-links a {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          padding: 8px 18px;
          border-radius: 100px;
          font-family: 'Inter', sans-serif;
          font-size: 0.78rem;
          font-weight: 500;
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .project-card-links .github-link {
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.06);
          color: rgba(255,255,255,0.7);
        }

        .project-card-links .github-link:hover {
          background: rgba(255,255,255,0.08);
          border-color: rgba(255,255,255,0.12);
          transform: translateY(-2px);
        }

        .project-card-links .demo-link {
          background: rgba(255,62,165,0.12);
          border: 1px solid rgba(255,62,165,0.15);
          color: #FF7CC7;
        }

        .project-card-links .demo-link:hover {
          background: rgba(255,62,165,0.2);
          border-color: rgba(255,62,165,0.25);
          transform: translateY(-2px);
          box-shadow: 0 4px 20px rgba(255,62,165,0.1);
        }

        /* Button */
        .btn-primary {
          display: inline-flex;
          align-items: center;
          gap: 10px;
          padding: 14px 32px;
          border-radius: 100px;
          background: rgba(255,62,165,0.12);
          border: 1px solid rgba(255,62,165,0.15);
          color: #FF7CC7;
          font-family: 'Inter', sans-serif;
          font-weight: 600;
          font-size: 0.9rem;
          text-decoration: none;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: pointer;
        }

        .btn-primary:hover {
          background: rgba(255,62,165,0.2);
          border-color: rgba(255,62,165,0.25);
          transform: translateY(-3px);
          box-shadow: 0 8px 32px rgba(255,62,165,0.12);
        }

        .btn-primary .arrow {
          transition: transform 0.3s ease;
        }

        .btn-primary:hover .arrow {
          transform: translateX(4px);
        }

        .btn-outline {
          display: inline-flex;
          align-items: center;
          gap: 10px;
          padding: 14px 32px;
          border-radius: 100px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.08);
          color: #F5F5F5;
          font-family: 'Inter', sans-serif;
          font-weight: 600;
          font-size: 0.9rem;
          text-decoration: none;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: pointer;
        }

        .btn-outline:hover {
          background: rgba(255,255,255,0.06);
          border-color: rgba(255,255,255,0.12);
          transform: translateY(-3px);
        }

        /* Stat */
        .stat-item {
          text-align: center;
          padding: 32px 24px;
          border-radius: 20px;
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.04);
          transition: all 0.4s ease;
        }

        .stat-item:hover {
          background: rgba(255,255,255,0.04);
          border-color: rgba(255,255,255,0.08);
          transform: translateY(-4px);
        }

        .stat-number {
          font-family: 'IBM Plex Mono', monospace;
          font-size: 3rem;
          font-weight: 600;
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
          line-height: 1;
        }

        .stat-label {
          font-family: 'Inter', sans-serif;
          font-size: 0.85rem;
          color: rgba(255,255,255,0.4);
          margin-top: 4px;
        }

        .section-title {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 800;
          font-size: 2.8rem;
          letter-spacing: -1px;
          color: #F5F5F5;
        }

        .section-title .highlight {
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .section-subtitle {
          font-family: 'Inter', sans-serif;
          font-size: 1rem;
          color: rgba(255,255,255,0.4);
          max-width: 500px;
          margin: 8px auto 0;
          line-height: 1.8;
        }

        .section-divider {
          width: 60px;
          height: 2px;
          margin: 20px auto;
          background: linear-gradient(90deg, transparent, #FF3EA5, transparent);
          border-radius: 2px;
        }

        /* Responsive */
        @media (max-width: 768px) {
          .main-content {
            padding-top: 80px;
          }
          .section-title {
            font-size: 2rem;
          }
          .stat-number {
            font-size: 2.2rem;
          }
          .project-card-img {
            height: 180px;
          }
          .floating-tag {
            display: none !important;
          }
        }

        @media (max-width: 576px) {
          .main-content {
            padding-top: 70px;
          }
          .section-title {
            font-size: 1.6rem;
          }
          .project-card-img {
            height: 150px;
          }
          .project-card-body {
            padding: 16px;
          }
          .btn-primary, .btn-outline {
            padding: 12px 24px;
            font-size: 0.8rem;
          }
          .tech-item {
            padding: 8px 16px;
          }
          .tech-item .icon {
            font-size: 1.1rem;
          }
          .tech-item .name {
            font-size: 0.75rem;
          }
        }
      `}</style>
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" />
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.7.2/css/all.min.css" />

      <div className="leopard-bg"></div>

      <Navbar />

      <div className="main-content" ref={containerRef}>
        {/* Hero Section */}
        <section style={{ padding: '0 0 40px' }}>
          <div className="container">
            <motion.div
              initial="hidden"
              animate="visible"
              variants={containerVariants}
              style={{ position: 'relative' }}
            >
              <div className="row align-items-center g-5">
                <div className="col-lg-6">
                  <motion.div variants={itemVariants}>
                    <div style={{ 
                      display: 'inline-block',
                      padding: '6px 16px',
                      borderRadius: '100px',
                      background: 'rgba(255,62,165,0.08)',
                      border: '1px solid rgba(255,62,165,0.1)',
                      fontSize: '0.75rem',
                      fontWeight: 500,
                      color: '#FF7CC7',
                      marginBottom: '20px',
                      letterSpacing: '0.5px',
                      textTransform: 'uppercase'
                    }}>
                      <i className="fas fa-code" style={{ marginRight: '8px' }}></i>
                      Software Engineer
                    </div>
                  </motion.div>

                  <motion.div variants={itemVariants}>
                    <h1 style={{
                      fontFamily: "'Space Grotesk', sans-serif",
                      fontSize: 'clamp(2.5rem, 6vw, 4.5rem)',
                      fontWeight: 900,
                      lineHeight: 1.05,
                      letterSpacing: '-2px',
                      color: '#F5F5F5',
                      marginBottom: '8px'
                    }}>
                      {nama}
                    </h1>
                  </motion.div>

                  <motion.div variants={itemVariants}>
                    <h2 style={{
                      fontFamily: "'Space Grotesk', sans-serif",
                      fontSize: 'clamp(1.2rem, 2.5vw, 2rem)',
                      fontWeight: 500,
                      color: 'rgba(255,255,255,0.3)',
                      marginBottom: '20px',
                      letterSpacing: '-0.5px'
                    }}>
                      <span style={{ color: '#FF7CC7' }}>
                        <AnimatePresence mode="wait">
                          <motion.span
                            key={roleIndex}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -10 }}
                            transition={{ duration: 0.5 }}
                          >
                            {roles[roleIndex]}
                          </motion.span>
                        </AnimatePresence>
                      </span>
                    </h2>
                  </motion.div>

                  <motion.div variants={itemVariants}>
                    <p style={{
                      fontFamily: "'Inter', sans-serif",
                      fontSize: '1rem',
                      color: 'rgba(255,255,255,0.5)',
                      lineHeight: 1.8,
                      maxWidth: '520px',
                      marginBottom: '32px'
                    }}>
                      {tentang}
                    </p>
                  </motion.div>

                  <motion.div variants={itemVariants} style={{ display: 'flex', gap: '12px', flexWrap: 'wrap', marginBottom: '32px' }}>
                    <Link to="/project" className="btn-primary">
                      <i className="fas fa-folder-open"></i>
                      View Projects
                      <span className="arrow"><i className="fas fa-arrow-right"></i></span>
                    </Link>
                    <a href="#skills" className="btn-outline">
                      <i className="fas fa-code"></i>
                      Skills
                    </a>
                  </motion.div>

                  <motion.div variants={itemVariants} style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                    <a href="https://github.com/ann4yaa" target="_blank" rel="noreferrer" style={{
                      width: '44px',
                      height: '44px',
